content:
:Stale | SessionState::Orphaned)
            );
            if has_stale_or_orphaned {
                reconnectable.push(agent);
            }
        }
        reconnectable.sort_by_key(|a| std::cmp::Reverse(a.last_seen));
        Ok(reconnectable)
    }
